public class ETG_CustKnockOffUIBuilder extends SrsReportDataContractUIBuilder
{
    ETG_CustKnockOffContract contract;
    public DialogField  financialDimensions;
    public DialogField  financialDimSet;

}

Method.Source:
public void postBuild()
{
    DialogField dialogField;

    super();

    contract = this.dataContractObject();

    financialDimensions = this.bindInfo().getDialogField(contract, methodStr(ETG_CustKnockOffContract, parmFinancialDimensions));
    financialDimensions.registerOverrideMethod(methodStr(FormCheckBoxControl, modified), methodStr(ETG_CustKnockOffUIBuilder, financialDimensionsModified), this);
    financialDimSet = this.bindInfo().getDialogField(contract, methodStr(ETG_CustKnockOffContract, parmFinancialDimSet));
    if (financialDimensions.value() == 1)
    {
        financialDimSet.enabled(true);
    }
    else
    {
        financialDimSet.enabled(false);
        financialDimSet.value("");
        contract.parmFinancialDimSet("");
    }
}

public  void build()
{
    //super();
    contract = this.dataContractObject();
    //financialDimensions = this.bindInfo().getDialogField(contract, methodStr(ETG_CustKnockOffContract, parmFinancialDimensions));
    this.addDialogField(methodStr(ETG_CustKnockOffContract,parmCustAccount),contract);
    this.addDialogField(methodStr(ETG_CustKnockOffContract,parmFromDate),contract);
    this.addDialogField(methodStr(ETG_CustKnockOffContract,parmToDate),contract);
    financialDimensions = this.addDialogField(methodStr(ETG_CustKnockOffContract, parmFinancialDimensions),contract);
    financialDimSet     = this.addDialogField(methodstr(ETG_CustKnockOffContract, parmFinancialDimSet), contract);
    financialDimSet.enabled(false);
    /*
    if (financialDimensions.value() == 1)
